#include <bits/stdc++.h>
using namespace std;
int n,ans[1025][1025];
void f(int x1,int y1,int x2,int y2){
    if(x1==x2 && y1==y2)return;
	int a=x1+(x2-x1+1)/2-1,b=y1+(y2-y1+1)/2-1;
	//cout<<x1<<' '<<y1<<' '<<x2<<' '<<y2<<'\n';
    for(int i=x1;i<=a;i++)
		for(int j=y1;j<=b;j++)ans[i][j]=0;
	f(x1,b+1,a,y2);
	f(a+1,b+1,x2,y2);
	f(a+1,y1,x2,b);
}
int main(){
    cin>>n;
    n=pow(2,n);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)ans[i][j]=1;
    f(1,1,n,n);
    for(int i=1;i<=n;i++){
    	for(int j=1;j<=n;j++)cout<<ans[i][j]<<' ';
    	cout<<endl;
    }
    return 0;
}
